"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["18062"],{25793(e){e.exports=JSON.parse('{"tag":{"label":"Ruby SDK","permalink":"/tags/ruby-sdk","allTagsPath":"/tags","count":20,"items":[{"id":"develop/ruby/asynchronous-activity","title":"Asynchronous Activity completion - Ruby SDK","description":"Asynchronously complete an Activity in Temporal using the Ruby SDK. Follow simple steps to allow an Activity Function to return without the Activity Execution completing.","permalink":"/develop/ruby/asynchronous-activity"},{"id":"develop/ruby/benign-exceptions","title":"Benign exceptions - Ruby SDK","description":"Mark expected or non-severe Activity errors as benign to reduce noise in logs, metrics, and OpenTelemetry traces.","permalink":"/develop/ruby/benign-exceptions"},{"id":"develop/ruby/child-workflows","title":"Child Workflows - Ruby SDK","description":"Start a Child Workflow Execution and set a Parent Close Policy using Temporal Ruby SDK.","permalink":"/develop/ruby/child-workflows"},{"id":"develop/ruby/continue-as-new","title":"Continue-As-New - Ruby SDK","description":"Use Continue-As-New with the Temporal Ruby SDK to manage Workflow Event Histories, ensuring optimal performance by starting new Executions seamlessly.","permalink":"/develop/ruby/continue-as-new"},{"id":"develop/ruby/converters-and-encryption","title":"Converters and encryption - Ruby SDK","description":"Use a custom Payload Codec and Converter in the Ruby SDK to modify Temporal Data Conversion behavior, including examples for encryption and formatting.","permalink":"/develop/ruby/converters-and-encryption"},{"id":"develop/ruby/core-application","title":"Core application - Ruby SDK","description":"Develop a basic Workflow and Activity Definition using the Temporal Ruby SDK, run a Worker Process, and set up Dynamic Workflows and Activities.","permalink":"/develop/ruby/core-application"},{"id":"develop/ruby/debugging","title":"Debugging - Ruby SDK","description":"Debug Workflows in development and production environments using Temporal Ruby SDK. Use logging, debugger, CLI, replay, tracing, and more.","permalink":"/develop/ruby/debugging"},{"id":"develop/ruby/durable-timers","title":"Durable Timers - Ruby SDK","description":"Set a Durable Timer using the Temporal Ruby SDK. Pause Workflow execution for days or months. Timers are persisted and efficient.","permalink":"/develop/ruby/durable-timers"},{"id":"develop/ruby/enriching-ui","title":"Enriching the user interface - Ruby SDK","description":"Add contextual information to workflows and events in the Temporal UI using the Ruby SDK.","permalink":"/develop/ruby/enriching-ui"},{"id":"develop/ruby/failure-detection","title":"Failure detection - Ruby SDK","description":"Optimize Workflow Execution with Temporal Ruby SDK - Set Timeouts, Retry Policies, and manage Activity Heartbeats efficiently.","permalink":"/develop/ruby/failure-detection"},{"id":"develop/ruby/interrupt-workflow","title":"Interrupt a Workflow - Ruby SDK","description":"Interrupt Workflow Execution in Ruby using the Temporal SDK. Cancel for graceful stops; terminate for forceful stops. Handle Cancellation in Workflow and Activities efficiently.","permalink":"/develop/ruby/interrupt-workflow"},{"id":"develop/ruby/observability","title":"Observability - Ruby SDK","description":"Explore Temporal SDK observability features for Metrics, Tracing, Logging, and Visibility using the Ruby SDK.","permalink":"/develop/ruby/observability"},{"id":"develop/ruby/rails-integration","title":"Rails integration - Ruby SDK","description":"Use the Temporal Ruby SDK with Ruby on Rails, including conventions for ActiveRecord, ActiveModel, and handling lazy/eager loading.","permalink":"/develop/ruby/rails-integration"},{"id":"develop/ruby/index","title":"Ruby SDK developer guide","description":"Use the Temporal Ruby SDK to develop Temporal Applications, connect to the Temporal Service, test Workflows and Activities, handle failures, send messages, and more.","permalink":"/develop/ruby/"},{"id":"develop/ruby/schedules","title":"Schedules - Ruby SDK","description":"Manage and optimize Scheduled Workflows using the Temporal Ruby SDK; Schedule, Create, Backfill, Update, Delete, Describe, List, Pause, Trigger, and more.","permalink":"/develop/ruby/schedules"},{"id":"develop/ruby/set-up-local-ruby","title":"Set up your local with the Ruby SDK","description":"Configure your local development environment to get started developing with Temporal","permalink":"/develop/ruby/set-up-local-ruby"},{"id":"develop/ruby/temporal-client","title":"Temporal Client - Ruby SDK","description":"Create a Temporal Client, connect to Temporal Cloud, start a Workflow, and get Workflow results using the Temporal Ruby SDK.","permalink":"/develop/ruby/temporal-client"},{"id":"develop/ruby/testing-suite","title":"Testing - Ruby SDK","description":"The Ruby test-suite guide covers Workflow and integration testing for Temporal. It includes end-to-end, integration, and unit testing, emphasizing the use of the test server to optimize test execution.","permalink":"/develop/ruby/testing-suite"},{"id":"develop/ruby/versioning","title":"Versioning - Ruby SDK","description":"Use the Ruby SDK Patching API to safely deploy new code versions, handle deprecated patches, and manage Workflow activities using Temporal for long-running tasks.","permalink":"/develop/ruby/versioning"},{"id":"develop/ruby/message-passing","title":"Workflow message passing - Ruby SDK","description":"Develop with Queries, Signals, and Updates using the Temporal Ruby SDK.","permalink":"/develop/ruby/message-passing"}],"unlisted":false}}')}}]);